import javax.swing.*;
import java.awt.*;

public class AWTandSwingHierarchy {
 public static void main(String[] args) {
 // Create a JFrame (Swing's top-level container)
 JFrame frame = new JFrame("AWT and Swing Hierarchy");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

 // Create a JPanel (Swing's container)
 JPanel panel = new JPanel();
 panel.setLayout(new BorderLayout());

 // Create an AWT Button and add it to the panel
 Button awtButton = new Button("AWT Button");
 panel.add(awtButton, BorderLayout.NORTH);

 // Create a Swing JButton and add it to the panel
 JButton swingButton = new JButton("Swing Button");
 panel.add(swingButton, BorderLayout.CENTER);

 // Add the panel to the frame
 frame.getContentPane().add(panel);
 frame.pack();
 frame.setVisible(true);
 }
}

import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class EventModel {
 public static void main(String[] args) {
 // Create a JFrame
 JFrame frame = new JFrame("Event Model");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

 // Create a JButton
 JButton button = new JButton("Click me");
 button.addActionListener(new ActionListener() {
 public void actionPerformed(ActionEvent e) {
 System.out.println("Button clicked");
 }
 });

 // Add the button to the frame
 frame.getContentPane().add(button);
 frame.pack();
 frame.setVisible(true);
 }
}
